import numpy as npimport flwr as flfrom flwr.common import Parameters, FitRes, Scalar, ndarrays_to_parameters, parameters_to_ndarraysfrom flwr.server.client_proxy import ClientProxyfrom typing import Dict, List, Optional, Tuple, Unionclass TrustFedAvg(fl.server.strategy.FedAvg):    def __init__(        self,        num_clients:     int   = 10,        num_rounds:      int   = 30,        alpha:           float = 0.3,    # EMA factor        beta:            float = 0.5,    # late-round penalty intensity        trust_threshold: float = 0.1,    # exclusion floor        **kwargs    ):        super().__init__(**kwargs)        self.num_clients     = num_clients        self.num_rounds      = num_rounds        self.alpha           = alpha        self.beta            = beta        self.trust_threshold = trust_threshold        self.current_round   = 0        # Initialise all clients at neutral trust        self.trust_scores: Dict[str, float] = {            str(i): 0.5 for i in range(num_clients)        }        # Full trust history — used for visualisation in Layer 5        self.trust_history: Dict[str, List[float]] = {            str(i): [] for i in range(num_clients)        }        # Track exclusions per round — for results chapter        self.exclusion_log: List[Dict] = []#Trust Calculation core ────────────────────────────    def _flatten(self, parameters: List[np.ndarray]) -> np.ndarray:        return np.concatenate([p.flatten() for p in parameters])    def _cosine_similarity(self, u: np.ndarray, v: np.ndarray) -> float:        norm_u = np.linalg.norm(u)        norm_v = np.linalg.norm(v)        if norm_u == 0 or norm_v == 0:            return 0.0        return float(np.clip(np.dot(u, v) / (norm_u * norm_v), -1.0, 1.0))    def _compute_reference(self, updates: List[np.ndarray]) -> np.ndarray:        return np.mean(updates, axis=0)    def _ema_update(self, client_id: str, cos_sim: float) -> float:          normalised        = (cos_sim + 1) / 2                # If client_id not recognised, initialise it at neutral trust        if client_id not in self.trust_scores:            self.trust_scores[client_id]  = 0.5            self.trust_history[client_id] = []                                old               = self.trust_scores[client_id]        updated           = self.alpha * normalised + (1 - self.alpha) * old        self.trust_scores[client_id] = updated        self.trust_history[client_id].append(round(updated, 4))        return updated    def _late_round_penalty(self, trust: float) -> float:        progress = self.current_round / self.num_rounds        penalty  = 1 - (progress * self.beta * (1 - trust))        return trust * max(penalty, 0.0)#Core Aggregation ─────────────────────────────────    def aggregate_fit(self, server_round: int, results: List[Tuple[ClientProxy, FitRes]], failures: List[Union[BaseException, Tuple[ClientProxy, FitRes]]],) -> Tuple[Optional[Parameters], Dict[str, Scalar]]:        self.current_round = server_round        if not results:            return None, {}        #Extract updates ────────────────────        client_data = []        for client_proxy, fit_res in results:            params    = parameters_to_ndarrays(fit_res.parameters)            flat      = self._flatten(params)            client_id = str(fit_res.metrics.get("client_id", f"unknown_{id}"))                        #client_id = str(fit_res.metrics.get("client_id", "unknown"))   #updated for the error            client_data.append({                "id":         client_id,                "flat":       flat,                "params":     params,                "n_samples":  fit_res.num_examples,                "fit_res":    fit_res,            })        #Reference direction ───────        all_updates = [cd["flat"] for cd in client_data]        reference   = self._compute_reference(all_updates)        # Score each client ───────        round_exclusions = []        trusted_data     = []                print(f"\n[ROUND {server_round}] Trust Scores:")        for cd in client_data:            cos_sim   = self._cosine_similarity(cd["flat"], reference)            trust     = self._ema_update(cd["id"], cos_sim)            penalised = self._late_round_penalty(trust)            status = "✓"            if penalised < self.trust_threshold:                status = "✗ EXCLUDED"                round_exclusions.append(cd["id"])            else:                trusted_data.append((cd, penalised))            print(f"  Client {cd['id']:>2}: "                  f"cos_sim={cos_sim:+.3f}  "                  f"trust={trust:.3f}  "                  f"penalised={penalised:.3f}  {status}")        # Log exclusions        self.exclusion_log.append({            "round":    server_round,            "excluded": round_exclusions        })        #Trust-weighted aggregation ─────────────────        if not trusted_data:            print("  [WARNING] All clients excluded — falling back to FedAvg")                                    #Safety fallback: use all clients if trust system excludes everyone            trusted_data = [(cd, 0.5) for cd in client_data]        aggregated = None        total_trust = sum(trust for _, trust in trusted_data)        for cd, trust in trusted_data:            weight = trust / total_trust   #normalised weight            if aggregated is None:                aggregated = [weight * layer for layer in cd["params"]]            else:                for j, layer in enumerate(cd["params"]):                    aggregated[j] += weight * layer        parameters_aggregated = ndarrays_to_parameters(aggregated)        #Summary line for quick reading        n_excluded = len(round_exclusions)        print(f"  → {len(trusted_data)} trusted, "              f"{n_excluded} excluded "              f"{'(' + ', '.join(f'Client {x}' for x in round_exclusions) + ')' if n_excluded else ''}")        return parameters_aggregated, {}    def get_trust_summary(self) -> Dict:        return {            "trust_scores_final": self.trust_scores,            "trust_history":      self.trust_history,            "exclusion_log":      self.exclusion_log,        }